sql:
SELECT SUM(total_amount) AS TotalAmount
FROM property_bookings
WHERE property_id = 0;

external_knowledge:
; Property expenses refer to the total amount spent on each property; 
; Confirmed bookings are those with a payment date; 
; A property profile includes its expenses, booking details, owner information, and manager information.

- 'identity cards' refers to property_id and property_name; 
- 'most prized properties' refers to properties with 'confirmed' booking status; 
- 'average scores' refers to the average rating given by guests; 
- 'number of times they have been crowned' refers to the total bookings for each property.

sql:
SELECT properties.property_name, properties.property_type, bookings.status
FROM properties
JOIN bookings ON properties.property_id = bookings.property_id;

SELECT property_id, COUNT(*) AS total_bookings
FROM property_bookings
GROUP BY property_id;
